Here's the full implementation:

**XAML — wrap CollectionView in RefreshView for pull-to-refresh:**

```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             xmlns:models="clr-namespace:MyApp.Models"
             xmlns:vm="clr-namespace:MyApp.ViewModels"
             x:Class="MyApp.Views.ItemsPage"
             x:DataType="vm:ItemsViewModel">

    <RefreshView IsRefreshing="{Binding IsRefreshing}"
                 Command="{Binding RefreshCommand}">
        <CollectionView ItemsSource="{Binding Items}"
                        SelectionMode="Single"
                        SelectedItem="{Binding SelectedItem, Mode=TwoWay}"
                        SelectionChangedCommand="{Binding ItemSelectedCommand}">
            <CollectionView.ItemsLayout>
                <LinearItemsLayout Orientation="Vertical"
                                   ItemSizingStrategy="MeasureFirstItem" />
            </CollectionView.ItemsLayout>
            <CollectionView.ItemTemplate>
                <DataTemplate x:DataType="models:Item">
                    <Grid Padding="12" ColumnDefinitions="48,*">
                        <Image Source="{Binding Icon}"
                               WidthRequest="40" HeightRequest="40" />
                        <VerticalStackLayout Grid.Column="1" VerticalOptions="Center">
                            <Label Text="{Binding Name}" FontAttributes="Bold" />
                            <Label Text="{Binding Description}"
                                   FontSize="12" TextColor="Gray" />
                        </VerticalStackLayout>
                    </Grid>
                </DataTemplate>
            </CollectionView.ItemTemplate>
            <CollectionView.EmptyView>
                <ContentView>
                    <Label Text="No items found."
                           HorizontalOptions="Center" VerticalOptions="Center" />
                </ContentView>
            </CollectionView.EmptyView>
        </CollectionView>
    </RefreshView>
</ContentPage>
```

**ViewModel — using CommunityToolkit.Mvvm:**

```csharp
using CommunityToolkit.Mvvm.ComponentModel;
using CommunityToolkit.Mvvm.Input;
using System.Collections.ObjectModel;

public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;

    public ItemsViewModel(IApiService api)
    {
        _api = api;
    }

    public ObservableCollection<Item> Items { get; } = new();

    [ObservableProperty]
    private Item? _selectedItem;

    [ObservableProperty]
    private bool _isRefreshing;

    [RelayCommand]
    private async Task ItemSelectedAsync()
    {
        if (SelectedItem is null) return;

        await Shell.Current.GoToAsync($"detail?id={SelectedItem.Id}");

        // Clear selection so user can re-select the same item later
        SelectedItem = null;
    }

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            Items.Clear();
            foreach (var item in data)
                Items.Add(item);
        }
        finally
        {
            // Must set false to hide the refresh spinner
            IsRefreshing = false;
        }
    }
}
```

**Key binding relationships:**

| XAML Property | ViewModel Property | Purpose |
|---|---|---|
| `IsRefreshing` | `IsRefreshing` (bool) | Controls spinner visibility; **must be set to `false`** when done |
| `Command` (RefreshView) | `RefreshCommand` | Triggers API reload on pull |
| `SelectedItem` | `SelectedItem` (TwoWay) | Tracks the selected item |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Fires navigation on selection |
| `ItemsSource` | `Items` (ObservableCollection) | Use `ObservableCollection<T>` so adds/removes auto-update UI |

**Important notes:**
- **Reset `SelectedItem = null`** after navigating — otherwise tapping the same item again won't fire the command.
- **Set `IsRefreshing = false`** in a `finally` block so the spinner always hides, even on errors.
- **`MeasureFirstItem`** on the layout improves scroll performance for uniform-height rows.
- **`x:DataType`** on both the page and the `DataTemplate` enables compiled bindings.
